import { Injectable, inject } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable, map } from 'rxjs';
import { environment } from '../../../environments/environment';
import { AlumnoRequest, AlumnoResponse } from '../models/alumno.model';

@Injectable({
  providedIn: 'root'
})
export class DocenteService {
  private http = inject(HttpClient);
  private apiUrl = environment.apiUrl + '/usuarios/docentes';

  listarDocentes(page = 0, size = 20, search = ''): Observable<any> {
    let params = new HttpParams().set('page', page).set('size', size);
    if (search.trim()) params = params.set('search', search.trim());
    return this.http.get<any>(this.apiUrl, { params });
  }

  crearDocente(docente: AlumnoRequest): Observable<AlumnoResponse> {
    return this.http.post<AlumnoResponse>(this.apiUrl, docente);
  }

  editarDocente(id: number, docente: AlumnoRequest): Observable<AlumnoResponse> {
    return this.http.put<AlumnoResponse>(`${this.apiUrl}/${id}`, docente);
  }

  cambiarEstado(id: number, estado: boolean): Observable<void> {
    return this.http.patch<void>(`${this.apiUrl}/${id}/estado`, { estado });
  }
}
